import { describe, it, expect, beforeEach, vi } from 'vitest';
import request from 'supertest';
import express from 'express';

vi.mock('../../src/repositories/ordersRepo');
vi.mock('../../src/repositories/orderDetailsRepo');
vi.mock('../../src/repositories/productsRepo');

import orderRouter from '../../src/routes/order';
import { getOrdersRepository } from '../../src/repositories/ordersRepo';
import { getOrderDetailsRepository } from '../../src/repositories/orderDetailsRepo';
import { getProductsRepository } from '../../src/repositories/productsRepo';

const mockOrdersRepo = {
  findAll: vi.fn(),
  findById: vi.fn(),
  create: vi.fn(),
  update: vi.fn(),
  delete: vi.fn(),
};

const mockOrderDetailsRepo = {
  create: vi.fn(),
};

const mockProductsRepo = {
  findById: vi.fn(),
  checkStock: vi.fn(),
  decrementStock: vi.fn(),
};

const baseOrder = {
  orderId: 1,
  branchId: 1,
  orderDate: '2026-01-15T10:00:00Z',
  name: 'Test Order',
  description: 'A test order',
  status: 'pending',
};

let app: express.Express;

beforeEach(() => {
  vi.clearAllMocks();
  vi.mocked(getOrdersRepository).mockResolvedValue(mockOrdersRepo as any);
  vi.mocked(getOrderDetailsRepository).mockResolvedValue(mockOrderDetailsRepo as any);
  vi.mocked(getProductsRepository).mockResolvedValue(mockProductsRepo as any);

  app = express();
  app.use(express.json());
  app.use('/orders', orderRouter);
});

describe('Orders route — happy paths', () => {
  it('GET / returns 200 with all orders', async () => {
    mockOrdersRepo.findAll.mockResolvedValue([baseOrder, { ...baseOrder, orderId: 2 }]);

    const res = await request(app).get('/orders');

    expect(res.status).toBe(200);
    expect(res.body).toHaveLength(2);
    expect(res.body[0]).toMatchObject({ orderId: 1, status: 'pending' });
  });

  it('GET /:id returns 200 with the order', async () => {
    mockOrdersRepo.findById.mockResolvedValue(baseOrder);

    const res = await request(app).get('/orders/1');

    expect(res.status).toBe(200);
    expect(res.body).toMatchObject({ orderId: 1, name: 'Test Order' });
  });

  it('GET /:id returns 404 when order does not exist', async () => {
    mockOrdersRepo.findById.mockResolvedValue(null);

    const res = await request(app).get('/orders/9999');

    expect(res.status).toBe(404);
  });

  it('POST / creates an order and returns 201', async () => {
    const payload = {
      branchId: 1,
      orderDate: '2026-03-01T00:00:00Z',
      name: 'New Order',
      description: 'A new order',
      status: 'pending',
    };
    mockOrdersRepo.create.mockResolvedValue({ ...payload, orderId: 3 });

    const res = await request(app).post('/orders').send(payload);

    expect(res.status).toBe(201);
    expect(res.body).toMatchObject({ orderId: 3, name: 'New Order' });
  });

  it('PUT /:id updates an order and returns 200', async () => {
    const updated = { ...baseOrder, status: 'shipped' };
    mockOrdersRepo.update.mockResolvedValue(updated);

    const res = await request(app).put('/orders/1').send({ status: 'shipped' });

    expect(res.status).toBe(200);
    expect(res.body).toMatchObject({ orderId: 1, status: 'shipped' });
  });

  it('DELETE /:id removes an order and returns 204', async () => {
    mockOrdersRepo.delete.mockResolvedValue(undefined);

    const res = await request(app).delete('/orders/1');

    expect(res.status).toBe(204);
  });
});
